parameters.jsCode:
const content = $input.first().json.choices[0].message.content;
let scripts = [];
try {
  const clean = content.replace(/```json\n?|\n?```/g, '').trim();
  const parsed = JSON.parse(clean);
  if (parsed.scripts && Array.isArray(parsed.scripts)) {
    scripts = parsed.scripts;
  }
} catch(e) {
  const parts = content.split(/\n(?:Video\s+)?Script\s+[#]?\d+/i).filter(s => s.trim().length > 100);
  scripts = parts.slice(0, 3);
}
if (scripts.length === 0) {
  const chunks = content.split(/\n\n+/).filter(s => s.trim().length > 80);
  scripts = chunks.slice(0, 3);
}
return scripts.slice(0, 3).map(s => ({json: {prompt: s.trim()}}));

